import sys
input = sys.stdin.readline
def main():
    n = int(input())
    a = list(map(int,input().split()))
    b = []
    for i in range(n):
        b.append(a[i])
        for j in range(i+1,n):
            b.append(a[j])
            for k in range(j+1,n):
                b.append(a[k])
    b.sort()
    c = []
    for i in range(len(b)):
        if b[i] not in c:
            c.append(b[i])
    print(len(c)+1)
main()
